@Test
public void bigEndianZeroBitsRead() throws Exception {
    ByteArrayInputStream in = new ByteArrayInputStream(new byte[] {
            42 // 00101010
        });
    BitInputStream bin = new BitInputStream(in, ByteOrder.BIG_ENDIAN);
    assertEquals(0, bin.readBits(0));
    assertEquals(42, bin.readBits(8));
}

@Test
public void littleEndianZeroBitsRead() throws Exception {
    ByteArrayInputStream in = new ByteArrayInputStream(new byte[] {
            42 // 00101010
        });
    BitInputStream bin = new BitInputStream(in, ByteOrder.LITTLE_ENDIAN);
    assertEquals(0, bin.readBits(0));
    assertEquals(42, bin.readBits(8));
}

@Test
public void bigEndianMultipleReadsWithBoundary() throws Exception {
    ByteArrayInputStream in = new ByteArrayInputStream(new byte[] {
            (byte)255, // 11111111
            (byte)170, // 10101010
            85         // 01010101
        });
    BitInputStream bin = new BitInputStream(in, ByteOrder.BIG_ENDIAN);
    assertEquals(255, bin.readBits(8));
    assertEquals(10, bin.readBits(4));
    assertEquals(10, bin.readBits(4));
    assertEquals(5, bin.readBits(4));
    assertEquals(5, bin.readBits(4));
}

@Test
public void littleEndianSingleBitReads() throws Exception {
    ByteArrayInputStream in = new ByteArrayInputStream(new byte[] {
            (byte)170 // 10101010
        });
    BitInputStream bin = new BitInputStream(in, ByteOrder.LITTLE_ENDIAN);
    assertEquals(0, bin.readBits(1));
    assertEquals(1, bin.readBits(1));
    assertEquals(0, bin.readBits(1));
    assertEquals(1, bin.readBits(1));
    assertEquals(0, bin.readBits(1));
    assertEquals(1, bin.readBits(1));
    assertEquals(0, bin.readBits(1));
    assertEquals(1, bin.readBits(1));
}
